/**
 * Relationship Evolution Engine
 *
 * Manages dynamic NPC relationships that evolve based on in-game interactions.
 * Uses simple TEXT descriptions instead of complex numerical systems.
 *
 * Philosophy: "AIlon hates Zuckerborg for that thing he did on Titan"
 * - Simple text descriptions
 * - Generated by LLM based on interactions
 * - Evolves naturally over time
 * - No complex matrices or calculations
 */

import {
  actorRelationships,
  and,
  db,
  desc,
  eq,
  gte,
  npcInteractions,
  or,
} from "@feed/db";
import { generateSnowflakeId, logger } from "@feed/shared";
import type { FeedLLMClient } from "./llm/openai-client";
import { StaticDataRegistry } from "./services/static-data-registry";
import { isSimulationMode } from "./storage-bridge";
import type { Actor, ActorRelationship, Organization } from "./types/shared";
import { first } from "./utils/array-utils";

export interface RelationshipChange {
  actor1Id: string;
  actor2Id: string;
  action: "create" | "update" | "delete";
  newHistory?: string; // The text description
  newType?: string;
  newSentiment?: number;
  newStrength?: number;
  reason: string;
}

export interface Interaction {
  actor1Id: string;
  actor2Id: string;
  type: "mention" | "reply" | "article" | "event" | "trade";
  sentiment: number;
  context: string;
  timestamp: Date;
}

export class RelationshipEvolutionEngine {
  constructor(private llm?: FeedLLMClient) {}

  /**
   * Generate initial relationships on first game tick
   * Simple algorithm based on affiliations and domains
   */
  async generateInitialRelationships(
    actors: Actor[],
    organizations: Organization[],
  ): Promise<number> {
    // In simulation mode, relationships are not persisted to DB
    if (isSimulationMode()) {
      logger.debug(
        "Skipping initial relationships in simulation mode",
        undefined,
        "RelationshipEvolutionEngine",
      );
      return 0;
    }

    logger.info(
      "Generating initial NPC relationships...",
      undefined,
      "RelationshipEvolutionEngine",
    );

    let created = 0;
    const orgMap = new Map(organizations.map((o) => [o.id, o]));

    // Simple algorithm: Create relationships between actors with shared context
    for (let i = 0; i < actors.length; i++) {
      const actor1 = actors[i]!;

      // Each actor gets 3-8 relationships
      const targetCount = 3 + Math.floor(Math.random() * 6);
      let relationshipCount = 0;

      for (
        let j = i + 1;
        j < actors.length && relationshipCount < targetCount;
        j++
      ) {
        const actor2 = actors[j]!;

        // Calculate simple compatibility
        const sharedOrgs =
          actor1.affiliations?.filter((org) =>
            actor2.affiliations?.includes(org),
          ) || [];

        const sharedDomains =
          actor1.domain?.filter((d) => actor2.domain?.includes(d)) || [];

        const hasSharedContext =
          sharedOrgs.length > 0 || sharedDomains.length > 0;
        const randomChance = Math.random() > 0.7; // 30% chance even without shared context

        if (hasSharedContext || randomChance) {
          // Generate simple text description using LLM if available, otherwise use templates
          let history: string;
          let type: string;
          let sentiment: number;

          if (this.llm && sharedOrgs.length > 0) {
            // LLM-DRIVEN: Generate relationship from context
            const org = orgMap.get(first(sharedOrgs)!);
            const context = `both affiliated with ${org?.name || "same organization"}`;

            // Check if relationship already exists
            const [existing] = await db
              .select()
              .from(actorRelationships)
              .where(
                or(
                  and(
                    eq(actorRelationships.actor1Id, actor1.id),
                    eq(actorRelationships.actor2Id, actor2.id),
                  ),
                  and(
                    eq(actorRelationships.actor1Id, actor2.id),
                    eq(actorRelationships.actor2Id, actor1.id),
                  ),
                ),
              )
              .limit(1);

            const llmResult = await this.generateInitialRelationshipDescription(
              actor1.name,
              actor2.name,
              context,
              actor1.personality || "",
              actor2.personality || "",
              existing?.history || undefined,
            );

            history = llmResult.description;
            type = llmResult.type;
            sentiment = llmResult.sentiment;
          } else if (sharedOrgs.length > 0) {
            // Fallback: Simple template
            const fallbackOrgId = first(sharedOrgs)!;
            const org = orgMap.get(fallbackOrgId);
            const orgName = org?.name.toLowerCase() || "same company";
            history = `both work at ${orgName}`;
            type = "acquaintances";
            sentiment = Math.random() * 0.6 - 0.3;
          } else if (sharedDomains.length > 0) {
            history = `both work in ${sharedDomains[0]}`;
            type = "acquaintances";
            sentiment = Math.random() * 0.4 - 0.2;
          } else {
            history = "professional circles";
            type = "acquaintances";
            sentiment = 0;
          }

          // Create relationship (use insert with conflict handling to avoid duplicates)
          // Check if relationship already exists first
          const [existingRel] = await db
            .select({ id: actorRelationships.id })
            .from(actorRelationships)
            .where(
              or(
                and(
                  eq(actorRelationships.actor1Id, actor1.id),
                  eq(actorRelationships.actor2Id, actor2.id),
                ),
                and(
                  eq(actorRelationships.actor1Id, actor2.id),
                  eq(actorRelationships.actor2Id, actor1.id),
                ),
              ),
            )
            .limit(1);

          if (!existingRel) {
            await db.insert(actorRelationships).values({
              id: await generateSnowflakeId(),
              actor1Id: actor1.id,
              actor2Id: actor2.id,
              relationshipType: type,
              strength: 0.3 + Math.random() * 0.5,
              sentiment,
              history,
              isPublic: true,
              updatedAt: new Date(),
              interactionCount: 0,
              evolutionCount: 0,
            });
          }

          created++;
          relationshipCount++;
        }
      }
    }

    logger.info(
      `Created ${created} initial relationships`,
      { count: created },
      "RelationshipEvolutionEngine",
    );
    return created;
  }

  /**
   * Generate initial relationship description using LLM (emergent, not hardcoded)
   */
  private async generateInitialRelationshipDescription(
    actor1Name: string,
    actor2Name: string,
    context: string,
    personality1: string,
    personality2: string,
    existingRelationship?: string,
  ): Promise<{ description: string; type: string; sentiment: number }> {
    const prompt = `Analyze the relationship between two NPCs:

NPC 1: ${actor1Name} (${personality1})
NPC 2: ${actor2Name} (${personality2})
Context: ${context}
${existingRelationship ? `Previous relationship: ${existingRelationship}` : "No previous relationship"}

Write a natural, casual description of their relationship. Be specific and narrative.

Examples of good descriptions:
- "competing for dominance after that ai board drama"
- "allies since working together on the rocket launch"
- "professional acquaintances in the tech scene"
- "used to work together but had a falling out over patents"

Guidelines:
- Keep it lowercase and casual
- Be specific to events/context when possible
- Around 100-200 characters is ideal (but can be longer if needed for context)
- Natural narrative style

Also determine:
- Type: allies, rivals, friends, enemies, acquaintances, or neutral
- Sentiment: -1.0 (hostile) to 1.0 (friendly)

Return JSON: { "description": "...", "type": "...", "sentiment": 0.0 }`;

    if (!this.llm) {
      throw new Error(
        "LLM client required for generateRelationshipDescription",
      );
    }

    const response = await this.llm.generateJSON<{
      description: string;
      type: string;
      sentiment: number;
    }>(
      prompt,
      { required: ["description", "type", "sentiment"] },
      { maxTokens: 200, temperature: 0.9 },
    );

    return {
      description: response.description.toLowerCase().trim(),
      type: response.type || "acquaintances",
      sentiment: Math.max(-1, Math.min(1, response.sentiment || 0)),
    };
  }

  /**
   * Track an interaction between two NPCs
   */
  async trackInteraction(
    interaction: Omit<Interaction, "timestamp">,
  ): Promise<void> {
    // In simulation mode, interactions are not persisted to DB
    if (isSimulationMode()) {
      return;
    }

    // Sort IDs to ensure consistency
    const sorted = [interaction.actor1Id, interaction.actor2Id].sort();
    const [id1, id2] = sorted as [string, string];

    await db.insert(npcInteractions).values({
      id: await generateSnowflakeId(),
      actor1Id: id1,
      actor2Id: id2,
      interactionType: interaction.type,
      sentiment: interaction.sentiment,
      context: interaction.context,
      timestamp: new Date(),
    });
  }

  /**
   * Analyze recent interactions and generate relationship updates using LLM
   * This is the KEY method - uses LLM to generate natural text descriptions
   */
  async analyzeAndUpdateRelationships(): Promise<number> {
    // In simulation mode, relationships are not persisted to DB
    if (isSimulationMode()) {
      return 0;
    }

    if (!this.llm) {
      logger.warn(
        "No LLM client available, skipping relationship analysis",
        undefined,
        "RelationshipEvolutionEngine",
      );
      return 0;
    }

    // Get recent interactions (last 7 days)
    const sevenDaysAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
    const recentInteractions = await db
      .select()
      .from(npcInteractions)
      .where(gte(npcInteractions.timestamp, sevenDaysAgo))
      .orderBy(desc(npcInteractions.timestamp))
      .limit(100); // Limit to prevent token overflow

    if (recentInteractions.length === 0) {
      logger.info(
        "No recent interactions to analyze",
        undefined,
        "RelationshipEvolutionEngine",
      );
      return 0;
    }

    // Group interactions by actor pair
    const pairInteractions = new Map<string, typeof recentInteractions>();

    for (const interaction of recentInteractions) {
      const pairKey = `${interaction.actor1Id}_${interaction.actor2Id}`;
      if (!pairInteractions.has(pairKey)) {
        pairInteractions.set(pairKey, []);
      }
      pairInteractions.get(pairKey)?.push(interaction);
    }

    logger.info(
      `Analyzing ${pairInteractions.size} actor pairs for relationship changes`,
      {
        pairs: pairInteractions.size,
        interactions: recentInteractions.length,
      },
      "RelationshipEvolutionEngine",
    );

    let updated = 0;

    // Process each pair
    for (const [pairKey, interactions] of pairInteractions) {
      // Need at least 2 interactions to update relationship
      if (interactions.length < 2) continue;

      const [actor1Id, actor2Id] = pairKey.split("_");
      if (!actor1Id || !actor2Id) continue;

      // Get existing relationship
      const [existing] = await db
        .select()
        .from(actorRelationships)
        .where(
          and(
            eq(actorRelationships.actor1Id, actor1Id),
            eq(actorRelationships.actor2Id, actor2Id),
          ),
        )
        .limit(1);

      // Get actor names from static registry
      const actor1 = StaticDataRegistry.getActor(actor1Id);
      const actor2 = StaticDataRegistry.getActor(actor2Id);

      if (!actor1 || !actor2) continue;

      // Calculate average sentiment
      const avgSentiment =
        interactions.reduce((sum, i) => sum + i.sentiment, 0) /
        interactions.length;

      // Build context for LLM
      const interactionSummary = interactions
        .slice(0, 5)
        .map(
          (i) =>
            `- ${i.interactionType}: ${i.context} (sentiment: ${i.sentiment > 0 ? "+" : ""}${i.sentiment.toFixed(2)})`,
        )
        .join("\n");

      // Use LLM to generate natural text description with retry logic
      const prompt = `Analyze the evolving relationship between two NPCs based on their recent interactions.

NPC 1: ${actor1.name}
NPC 2: ${actor2.name}

Recent interactions (last 7 days):
${interactionSummary}

${existing ? `Current relationship: "${existing.history}"` : "No existing relationship"}

Based on these interactions, write a natural, casual description of how their relationship has evolved.

Guidelines:
- Lowercase and casual tone
- Specific to recent events when possible
- Natural narrative style (not telegraphic)
- Around 100-200 characters is good (but can be longer if the story needs it)
- Reference what actually happened

Examples:
- "used to compete but now working together after that ai safety thing"
- "allies since they collaborated on the teslai rocket launch last month"
- "hates each other now after that metaverse disaster and twitter drama"
- "professional relationship that's gotten tense after competing bids"

Also determine:
- Type: allies, rivals, friends, enemies, acquaintances, or neutral
- Sentiment: -1.0 (hostile) to 1.0 (friendly)

Return JSON: { "description": "...", "type": "...", "sentiment": 0.0 }`;

      // Retry logic: up to 3 attempts with LLM-generated relationship updates
      let newHistory = "professional relationship";
      let newType = "acquaintances";
      let newSentiment = avgSentiment;
      const maxRetries = 3;

      for (let attempt = 0; attempt < maxRetries; attempt++) {
        const response = await this.llm.generateJSON<{
          description: string;
          type: string;
          sentiment: number;
        }>(
          prompt,
          { required: ["description", "type", "sentiment"] },
          {
            maxTokens: 200,
            temperature: 0.8,
            promptType: "relationship_evolve",
          },
        );

        if (response.description && response.description.trim().length > 0) {
          // LLM determines everything - no hardcoded rules
          // Don't trim - let LLM decide length (they know the context)
          newHistory = response.description.toLowerCase().trim();
          newType = response.type || "acquaintances";
          newSentiment = Math.max(
            -1,
            Math.min(1, response.sentiment || avgSentiment),
          );
          break; // Success
        }

        // Wait before retry (exponential backoff)
        if (attempt < maxRetries - 1) {
          await new Promise((resolve) =>
            setTimeout(resolve, 1000 * 2 ** attempt),
          );
        }
      }

      // Update or create relationship
      if (existing) {
        // Update existing
        await db
          .update(actorRelationships)
          .set({
            history: newHistory,
            relationshipType: newType,
            sentiment: newSentiment,
            strength: Math.min(
              1.0,
              (existing.strength || 0.5) + interactions.length * 0.05,
            ),
            lastInteraction: new Date(),
            interactionCount:
              (existing.interactionCount || 0) + interactions.length,
            evolutionCount: (existing.evolutionCount || 0) + 1,
            updatedAt: new Date(),
          })
          .where(eq(actorRelationships.id, existing.id));
      } else {
        // Create new
        await db.insert(actorRelationships).values({
          id: await generateSnowflakeId(),
          actor1Id,
          actor2Id,
          relationshipType: newType,
          strength: Math.min(0.7, interactions.length * 0.1),
          sentiment: newSentiment,
          history: newHistory,
          isPublic: true,
          lastInteraction: new Date(),
          interactionCount: interactions.length,
          evolutionCount: 0,
          updatedAt: new Date(),
        });
      }

      updated++;
      logger.info(
        "Updated relationship",
        {
          actor1: actor1.name,
          actor2: actor2.name,
          description: newHistory,
          type: newType,
          sentiment: newSentiment.toFixed(2),
        },
        "RelationshipEvolutionEngine",
      );
    }

    logger.info(
      `Updated ${updated} relationships`,
      { count: updated },
      "RelationshipEvolutionEngine",
    );
    return updated;
  }

  /**
   * Get relationship context for prompts - ULTRA SIMPLE
   * Just the text descriptions, nothing else
   */
  async getRelationshipContextForActor(actorId: string): Promise<string> {
    // In simulation mode, relationships are not persisted to DB
    if (isSimulationMode()) {
      return "";
    }

    // Get relationships for this actor
    const relationships = await db
      .select()
      .from(actorRelationships)
      .where(
        or(
          eq(actorRelationships.actor1Id, actorId),
          eq(actorRelationships.actor2Id, actorId),
        ),
      )
      .orderBy(desc(actorRelationships.strength))
      .limit(5); // Top 5 strongest only (keep it short)

    if (relationships.length === 0) {
      return "";
    }

    // Get the other actor IDs we need to look up
    const otherActorIds = relationships.map((rel) =>
      rel.actor1Id === actorId ? rel.actor2Id : rel.actor1Id,
    );

    // Get actor names from static registry
    const actorNameMap = new Map(
      otherActorIds.map((id) => {
        const actor = StaticDataRegistry.getActor(id);
        return [id, actor?.name || "Unknown"];
      }),
    );

    // SIMPLEST FORMAT: Just list the relationships
    const lines = relationships.map((rel) => {
      const otherActorId =
        rel.actor1Id === actorId ? rel.actor2Id : rel.actor1Id;
      const otherActorName = actorNameMap.get(otherActorId) || "Unknown";

      // Just the text description, no emojis or extra formatting
      return `- ${otherActorName}: ${rel.history || "professional relationship"}`;
    });

    return lines.join("\n");
  }

  // =============================================================================
  // STATIC QUERY METHODS (consolidated from RelationshipManager)
  // =============================================================================

  /**
   * Get all relationships for an actor (static method for queries)
   */
  static async getActorRelationships(
    actorId: string,
  ): Promise<ActorRelationship[]> {
    // In simulation mode, relationships are not persisted to DB
    if (isSimulationMode()) {
      return [];
    }

    const relationships = await db
      .select()
      .from(actorRelationships)
      .where(
        or(
          eq(actorRelationships.actor1Id, actorId),
          eq(actorRelationships.actor2Id, actorId),
        ),
      );

    return relationships.map((rel) => ({
      id: rel.id,
      actor1Id: rel.actor1Id,
      actor2Id: rel.actor2Id,
      relationshipType:
        rel.relationshipType as ActorRelationship["relationshipType"],
      strength: rel.strength,
      sentiment: rel.sentiment,
      isPublic: rel.isPublic,
      history: rel.history || undefined,
      affects: rel.affects as Record<string, number> | undefined,
      createdAt: rel.createdAt,
      updatedAt: rel.updatedAt,
    }));
  }

  /**
   * Get specific relationship between two actors
   */
  static async getRelationship(
    actor1Id: string,
    actor2Id: string,
  ): Promise<ActorRelationship | null> {
    // In simulation mode, relationships are not persisted to DB
    if (isSimulationMode()) {
      return null;
    }

    const [relationship] = await db
      .select()
      .from(actorRelationships)
      .where(
        or(
          and(
            eq(actorRelationships.actor1Id, actor1Id),
            eq(actorRelationships.actor2Id, actor2Id),
          ),
          and(
            eq(actorRelationships.actor1Id, actor2Id),
            eq(actorRelationships.actor2Id, actor1Id),
          ),
        ),
      )
      .limit(1);

    if (!relationship) return null;

    return {
      id: relationship.id,
      actor1Id: relationship.actor1Id,
      actor2Id: relationship.actor2Id,
      relationshipType:
        relationship.relationshipType as ActorRelationship["relationshipType"],
      strength: relationship.strength,
      sentiment: relationship.sentiment,
      isPublic: relationship.isPublic,
      history: relationship.history || undefined,
      affects: relationship.affects as Record<string, number> | undefined,
      createdAt: relationship.createdAt,
      updatedAt: relationship.updatedAt,
    };
  }
}
